 44→    private val recommendedInterests: LiveData<ReaderTagList> = mutableRecommendedInterests
 45→    private val followingReaderTag = readerUtilsWrapper.getTagFromTagName(ReaderConstants.KEY_FOLLOWING, DEFAULT)
 46→
 47→    suspend fun getInterests(): ReaderRepositoryCommunication {
 48→        return withContext(ioDispatcher) {
 49→            fetchInterestTagUseCase.fetch()
 50→        }
 51→    }
 52→
 53→    suspend fun getUserTags(): ReaderRepositoryCommunication {
 54→        return withContext(ioDispatcher) {
 55→            val userTags = getFollowedTagsUseCase.get()
 56→            if (userTags.isNotEmpty()) {
 57→                SuccessWithData(userTags)
 58→            } else {
 59→                val refresh = shouldAutoUpdateTagUseCase.get(followingReaderTag)
 60→                var result: ReaderRepositoryCommunication = Success
 61→                if (refresh) {
 62→                    result = fetchFollowedTagUseCase.fetch()
 63→                }
 64→                if (result is Success) {
 65→                    SuccessWithData(getFollowedTagsUseCase.get())
 66→                } else {
 67→                    result
 68→                }
 69→            }
 70→        }
 71→    }
