 73→    suspend fun saveInterests(tags: List<ReaderTag>): ReaderRepositoryCommunication {
 74→        return withContext(ioDispatcher) {
 75→            followInterestTagsUseCase.followInterestTags(tags)
 76→        }
 77→    }
 78→
 79→    suspend fun clearTagLastUpdated(tag: ReaderTag) {
 80→        withContext(ioDispatcher) {
 81→            readerTagTableWrapper.clearTagLastUpdated(tag)
 82→        }
 83→    }
 84→
 85→    suspend fun getRecommendedInterests(): LiveData<ReaderTagList> =
 86→        withContext(bgDispatcher) {
 87→            delay(TimeUnit.SECONDS.toMillis(5))
 88→            getMockRecommendedInterests()
 89→        }
