import org.wordpress.android.models.ReaderTag
import org.wordpress.android.models.ReaderTagType
import org.wordpress.android.ui.bloggingprompts.BloggingPromptsPostTagProvider
import org.junit.Assert.*
import org.junit.Test

/**
 * Test to verify that the dailyprompt tag is correctly filtered out
 * when checking if a user needs onboarding.
 */
class DailyPromptOnboardingTest {

    @Test
    fun `dailyprompt tag should be filtered out for onboarding check`() {
        // Simulate a new user with only dailyprompt tag
        val userTags = listOf(
            ReaderTag(
                BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG,
                BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG,
                "Daily Prompts",
                "endpoint",
                ReaderTagType.FOLLOWED
            )
        )

        // Filter out dailyprompt tags when checking for onboarding
        val userTagsExcludingDailyPrompt = userTags.filter { 
            !it.tagSlug.startsWith(BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG) 
        }

        // User should be considered as having no tags for onboarding
        assertTrue("User with only dailyprompt tag should show onboarding", 
            userTagsExcludingDailyPrompt.isEmpty())
    }

    @Test
    fun `user with dailyprompt and other tags should not show onboarding`() {
        // Simulate a user with dailyprompt tag and other tags
        val userTags = listOf(
            ReaderTag(
                BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG,
                BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG,
                "Daily Prompts",
                "endpoint",
                ReaderTagType.FOLLOWED
            ),
            ReaderTag(
                "technology",
                "Technology",
                "Technology",
                "endpoint",
                ReaderTagType.FOLLOWED
            )
        )

        // Filter out dailyprompt tags when checking for onboarding
        val userTagsExcludingDailyPrompt = userTags.filter { 
            !it.tagSlug.startsWith(BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG) 
        }

        // User should be considered as having tags and not show onboarding
        assertFalse("User with dailyprompt and other tags should not show onboarding", 
            userTagsExcludingDailyPrompt.isEmpty())
        assertEquals("Should have 1 non-dailyprompt tag", 1, userTagsExcludingDailyPrompt.size)
    }

    @Test
    fun `user with no tags should show onboarding`() {
        // Simulate a user with no tags
        val userTags = emptyList<ReaderTag>()

        // Filter out dailyprompt tags when checking for onboarding
        val userTagsExcludingDailyPrompt = userTags.filter { 
            !it.tagSlug.startsWith(BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG) 
        }

        // User should show onboarding
        assertTrue("User with no tags should show onboarding", 
            userTagsExcludingDailyPrompt.isEmpty())
    }

    @Test
    fun `dailyprompt with ID should be filtered out`() {
        // Simulate a user with dailyprompt-123 tag
        val userTags = listOf(
            ReaderTag(
                "${BloggingPromptsPostTagProvider.BLOGGING_PROMPT_ID_TAG_PREFIX}123",
                "Daily Prompt 123",
                "Daily Prompt 123",
                "endpoint",
                ReaderTagType.FOLLOWED
            )
        )

        // Filter out dailyprompt tags when checking for onboarding
        val userTagsExcludingDailyPrompt = userTags.filter { 
            !it.tagSlug.startsWith(BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG) 
        }

        // User should show onboarding
        assertTrue("User with dailyprompt-123 tag should show onboarding", 
            userTagsExcludingDailyPrompt.isEmpty())
    }
}"}

